import threading
import uuid
from datetime import datetime
from typing import Optional
from dataclasses import dataclass, field
from enum import Enum


class TransactionType(Enum):
    DEPOSIT = "deposit"
    WITHDRAWAL = "withdrawal"
    TRANSFER = "transfer"


class TransactionStatus(Enum):
    PENDING = "pending"
    COMPLETED = "completed"
    FAILED = "failed"
    ROLLED_BACK = "rolled_back"


@dataclass
class Transaction:
    transaction_id: str
    transaction_type: TransactionType
    amount: float
    source_account_id: Optional[str]
    destination_account_id: Optional[str]
    status: TransactionStatus
    timestamp: datetime
    idempotency_key: str


@dataclass
class Account:
    account_id: str
    balance: float = 0.0
    lock: threading.Lock = field(default_factory=threading.Lock)


class InsufficientFundsError(Exception):
    pass


class AccountNotFoundError(Exception):
    pass


class DuplicateTransactionError(Exception):
    pass


class InvalidTransactionError(Exception):
    pass


class FinancialProcessor:
    """
    Processes financial transactions with proper concurrency control.
    
    Uses per-account locks and a global transaction lock to ensure:
    - Atomic read-modify-write on account balances
    - Idempotent transaction processing (no double-spend)
    - Consistent ordering for transfers (deadlock prevention)
    """

    def __init__(self):
        self._accounts: dict[str, Account] = {}
        self._transactions: dict[str, Transaction] = {}
        self._idempotency_keys: dict[str, str] = {}  # idempotency_key -> transaction_id
        self._global_lock = threading.Lock()  # Protects account/transaction registry

    def create_account(self, account_id: str, initial_balance: float = 0.0) -> Account:
        """Create a new account with an optional initial balance."""
        if initial_balance < 0:
            raise ValueError("Initial balance cannot be negative")

        with self._global_lock:
            if account_id in self._accounts:
                raise ValueError(f"Account {account_id} already exists")
            account = Account(account_id=account_id, balance=initial_balance)
            self._accounts[account_id] = account
            return account

    def get_account(self, account_id: str) -> Account:
        """Retrieve an account by ID."""
        with self._global_lock:
            if account_id not in self._accounts:
                raise AccountNotFoundError(f"Account {account_id} not found")
            return self._accounts[account_id]

    def get_balance(self, account_id: str) -> float:
        """Get the current balance of an account (thread-safe read)."""
        account = self.get_account(account_id)
        with account.lock:
            return account.balance

    def _check_idempotency(self, idempotency_key: str) -> Optional[Transaction]:
        """
        Check if a transaction with this idempotency key was already processed.
        Must be called while holding the global lock.
        Returns the existing transaction if found, None otherwise.
        """
        if idempotency_key in self._idempotency_keys:
            existing_tx_id = self._idempotency_keys[idempotency_key]
            return self._transactions.get(existing_tx_id)
        return None

    def _record_transaction(self, transaction: Transaction) -> None:
        """
        Record a transaction and its idempotency key.
        Must be called while holding the global lock.
        """
        self._transactions[transaction.transaction_id] = transaction
        self._idempotency_keys[transaction.idempotency_key] = transaction.transaction_id

    def deposit(self, account_id: str, amount: float, idempotency_key: str) -> Transaction:
        """
        Deposit funds into an account.
        
        Uses idempotency key to prevent duplicate deposits.
        The balance update is performed atomically under the account lock.
        """
        if amount <= 0:
            raise InvalidTransactionError("Deposit amount must be positive")

        with self._global_lock:
            # Idempotency check under global lock
            existing = self._check_idempotency(idempotency_key)
            if existing is not None:
                if existing.status == TransactionStatus.COMPLETED:
                    return existing
                raise DuplicateTransactionError(
                    f"Transaction with idempotency key {idempotency_key} "
                    f"already exists with status {existing.status.value}"
                )

            if account_id not in self._accounts:
                raise AccountNotFoundError(f"Account {account_id} not found")

            account = self._accounts[account_id]
            transaction_id = str(uuid.uuid4())

            transaction = Transaction(
                transaction_id=transaction_id,
                transaction_type=TransactionType.DEPOSIT,
                amount=amount,
                source_account_id=None,
                destination_account_id=account_id,
                status=TransactionStatus.PENDING,
                timestamp=datetime.utcnow(),
                idempotency_key=idempotency_key,
            )

            # Record pending transaction under global lock to reserve idempotency key
            self._record_transaction(transaction)

        # Perform atomic balance update under account lock
        with account.lock:
            account.balance += amount
            transaction.status = TransactionStatus.COMPLETED

        return transaction

    def withdraw(self, account_id: str, amount: float, idempotency_key: str) -> Transaction:
        """
        Withdraw funds from an account.
        
        Authorization (sufficient funds check) and balance update are performed
        atomically under the same account lock to prevent race conditions.
        """
        if amount <= 0:
            raise InvalidTransactionError("Withdrawal amount must be positive")

        with self._global_lock:
            existing = self._check_idempotency(idempotency_key)
            if existing is not None:
                if existing.status == TransactionStatus.COMPLETED:
                    return existing
                raise DuplicateTransactionError(
                    f"Transaction with idempotency key {idempotency_key} "
                    f"already exists with status {existing.status.value}"
                )

            if account_id not in self._accounts:
                raise AccountNotFoundError(f"Account {account_id} not found")

            account = self._accounts[account_id]
            transaction_id = str(uuid.uuid4())

            transaction = Transaction(
                transaction_id=transaction_id,
                transaction_type=TransactionType.WITHDRAWAL,
                amount=amount,
                source_account_id=account_id,
                destination_account_id=None,
                status=TransactionStatus.PENDING,
                timestamp=datetime.utcnow(),
                idempotency_key=idempotency_key,
            )

            self._record_transaction(transaction)

        # Atomic check-and-update under account lock
        with account.lock:
            if account.balance < amount:
                transaction.status = TransactionStatus.FAILED
                raise InsufficientFundsError(
                    f"Account {account_id} has insufficient funds. "
                    f"Balance: {account.balance}, Requested: {amount}"
                )
            account.balance -= amount
            transaction.status = TransactionStatus.COMPLETED

        return transaction

    def transfer(
        self,
        source_account_id: str,
        destination_account_id: str,
        amount: float,
        idempotency_key: str,
    ) -> Transaction:
        """
        Transfer funds between two accounts atomically.
        
        Acquires locks on both accounts in a consistent order (sorted by account_id)
        to prevent deadlocks. The balance check and both updates happen within
        the same locked context.
        """
        if amount <= 0:
            raise InvalidTransactionError("Transfer amount must be positive")

        if source_account_id == destination_account_id:
            raise InvalidTransactionError("Cannot transfer to the same account")

        with self._global_lock:
            existing = self._check_idempotency(idempotency_key)
            if existing is not None:
                if existing.status == TransactionStatus.COMPLETED:
                    return existing
                raise DuplicateTransactionError(
                    f"Transaction with idempotency key {idempotency_key} "
                    f"already exists with status {existing.status.value}"
                )

            if source_account_id not in self._accounts:
                raise AccountNotFoundError(f"Source account {source_account_id} not found")
            if destination_account_id not in self._accounts:
                raise AccountNotFoundError(
                    f"Destination account {destination_account_id} not found"
                )

            source_account = self._accounts[source_account_id]
            dest_account = self._accounts[destination_account_id]

            transaction_id = str(uuid.uuid4())

            transaction = Transaction(
                transaction_id=transaction_id,
                transaction_type=TransactionType.TRANSFER,
                amount=amount,
                source_account_id=source_account_id,
                destination_account_id=destination_account_id,
                status=TransactionStatus.PENDING,
                timestamp=datetime.utcnow(),
                idempotency_key=idempotency_key,
            )

            self._record_transaction(transaction)

        # Acquire locks in consistent order to prevent deadlocks
        first_lock_account, second_lock_account = sorted(
            [source_account, dest_account], key=lambda a: a.account_id
        )

        with first_lock_account.lock:
            with second_lock_account.lock:
                # Atomic validation and update of both accounts
                if source_account.balance < amount:
                    transaction.status = TransactionStatus.FAILED
                    raise InsufficientFundsError(
                        f"Account {source_account_id} has insufficient funds. "
                        f"Balance: {source_account.balance}, Requested: {amount}"
                    )

                source_account.balance -= amount
                dest_account.balance += amount
                transaction.status = TransactionStatus.COMPLETED

        return transaction

    def get_transaction(self, transaction_id: str) -> Optional[Transaction]:
        """Retrieve a transaction by its ID."""
        with self._global_lock:
            return self._transactions.get(transaction_id)

    def get_transaction_by_idempotency_key(
        self, idempotency_key: str
    ) -> Optional[Transaction]:
        """Retrieve a transaction by its idempotency key."""
        with self._global_lock:
            tx_id = self._idempotency_keys.get(idempotency_key)
            if tx_id:
                return self._transactions.get(tx_id)
            return None


def process_financial_transactions(transactions_data: list[dict]) -> dict:
    """
    Process a batch of financial transactions and return results.
    
    Each transaction dict should contain:
    - type: "deposit", "withdrawal", or "transfer"
    - amount: float
    - account_id: str (for deposit/withdrawal)
    - source_account_id: str (for transfer)
    - destination_account_id: str (for transfer)
    - idempotency_key: str
    
    Returns a dict with results for each transaction.
    """
    processor = FinancialProcessor()
    results = {
        "processed": [],
        "failed": [],
        "total_processed": 0,
        "total_failed": 0,
    }

    # First pass: ensure all referenced accounts exist
    referenced_accounts = set()
    for tx_data in transactions_data:
        if tx_data.get("account_id"):
            referenced_accounts.add(tx_data["account_id"])
        if tx_data.get("source_account_id"):
            referenced_accounts.add(tx_data["source_account_id"])
        if tx_data.get("destination_account_id"):
            referenced_accounts.add(tx_data["destination_account_id"])

    for account_id in referenced_accounts:
        try:
            processor.create_account(
                account_id, initial_balance=tx_data.get("initial_balance", 0.0)
            )
        except ValueError:
            pass  # Account already exists

    for tx_data in transactions_data:
        try:
            idempotency_key = tx_data.get("idempotency_key", str(uuid.uuid4()))
            tx_type = tx_data.get("type", "").lower()

            if tx_type == "deposit":
                transaction = processor.deposit(
                    account_id=tx_data["account_id"],
                    amount=tx_data["amount"],
                    idempotency_key=idempotency_key,
                )
            elif tx_type == "withdrawal":
                transaction = processor.withdraw(
                    account_id=tx_data["account_id"],
                    amount=tx_data["amount"],
                    idempotency_key=idempotency_key,
                )
            elif tx_type == "transfer":
                transaction = processor.transfer(
                    source_account_id=tx_data["source_account_id"],
                    destination_account_id=tx_data["destination_account_id"],
                    amount=tx_data["amount"],
                    idempotency_key=idempotency_key,
                )
            else:
                raise InvalidTransactionError(f"Unknown transaction type: {tx_type}")

            results["processed"].append(
                {
                    "transaction_id": transaction.transaction_id,
                    "type": transaction.transaction_type.value,
                    "amount": transaction.amount,
                    "status": transaction.status.value,
                    "idempotency_key": transaction.idempotency_key,
                }
            )
            results["total_processed"] += 1

        except (
            InsufficientFundsError,
            AccountNotFoundError,
            DuplicateTransactionError,
            InvalidTransactionError,
        ) as e:
            results["failed"].append(
                {
                    "error": str(e),
                    "type": type(e).__name__,
                    "transaction_data": tx_data,
                }
            )
            results["total_failed"] += 1

    return results


def demonstrate_concurrent_safety():
    """Demonstrate that the processor is safe under concurrent access."""
    import concurrent.futures

    processor = FinancialProcessor()
    processor.create_account("alice", initial_balance=10000.0)
    processor.create_account("bob", initial_balance=10000.0)

    num_transfers = 100
    transfer_amount = 10.0

    def transfer_alice_to_bob(i):
        try:
            processor.transfer(
                source_account_id="alice",
                destination_account_id="bob",
                amount=transfer_amount,
                idempotency_key=f"a2b-{i}",
            )
            return "success"
        except InsufficientFundsError:
            return "insufficient_funds"

    def transfer_bob_to_alice(i):
        try:
            processor.transfer(
                source_account_id="bob",
                destination_account_id="alice",
                amount=transfer_amount,
                idempotency_key=f"b2a-{i}",
            )
            return "success"
        except InsufficientFundsError:
            return "insufficient_funds"

    with concurrent.futures.ThreadPoolExecutor(max_workers=20) as executor:
        futures = []
        for i in range(num_transfers):
            futures.append(executor.submit(transfer_alice_to_bob, i))
            futures.append(executor.submit(transfer_bob_to_alice, i))

        results = [f.result() for f in concurrent.futures.as_completed(futures)]

    alice_balance = processor.get_balance("alice")
    bob_balance = processor.get_balance("bob")
    total = alice_balance + bob_balance

    print(f"Alice's balance: {alice_balance}")
    print(f"Bob's balance: {bob_balance}")
    print(f"Total (should be 20000.0): {total}")
    print(f"Conservation of funds: {'PASS' if total == 20000.0 else 'FAIL'}")

    # Demonstrate idempotency: retry the same transfer
    try:
        tx1 = processor.deposit("alice", 500.0, "idem-test-1")
        tx2 = processor.deposit("alice", 500.0, "idem-test-1")  # Same key
        print(f"Idempotency: tx1_id == tx2_id: {tx1.transaction_id == tx2.transaction_id}")
        print("Idempotency protection: PASS")
    except DuplicateTransactionError:
        print("Idempotency protection: PASS (duplicate rejected)")

    return total == 20000.0


